UPDATE product
SET status = #{status}, published_at = #{publishedAt}, updated_at = #{updatedAt}
WHERE shop_id = #{shopId} AND id = #{id}

UPDATE product_variant
SET sku = #{sku}, title = #{title}, price_amount = #{priceAmount},
		price_currency = #{priceCurrency}, updated_at = #{updatedAt}
WHERE shop_id = #{shopId} AND id = #{id}
